**GraphQlTester — Spring's GraphQL test client:**

```java
// @GraphQlTest: loads only GraphQL layer (@Controller + schema)
@GraphQlTest(MerchantController.class)
class MerchantQueryTest {
    @Autowired GraphQlTester tester;
    @MockBean MerchantService merchantService; // mock the service

    @Test void merchant_query() {
        when(merchantService.findById("MRC-001"))
            .thenReturn(new Merchant("MRC-001", "Flipkart"));

        tester.documentName("getMerchant") // src/test/resources/graphql-test/getMerchant.graphql
            .variable("id", "MRC-001")
            .execute()
            .errors().verify()                           // no GraphQL errors
            .path("merchant.id").entity(String.class).isEqualTo("MRC-001")
            .path("merchant.name").entity(String.class).isEqualTo("Flipkart");
    }

    @Test void merchant_notFound_returnsError() {
        when(merchantService.findById("UNKNOWN")).thenReturn(null);

        tester.document("{ merchant(id: \"UNKNOWN\") { id name } }")
            .execute()
            .errors().satisfy(errors -> {
                assertFalse(errors.isEmpty());
                assertEquals("NOT_FOUND", errors.get(0).getErrorType().toString());
            });
    }
}
```

```graphql
# src/test/resources/graphql-test/getMerchant.graphql
query getMerchant($id: String!) {
  merchant(id: $id) {
    id
    name
    payments { id amount status }
  }
}
```

